const UNDERWRITING={"business": ["Εθνική & Επιχείρηση: Περιεχόμενο έως 900.000€ και συνολικό κεφάλαιο οικοδομής/περιεχομένου έως 4.400.000€.", "Εθνική & Επιχείρηση PLUS: συνολικό κεφάλαιο οικοδομής/βελτιώσεων/περιεχομένου έως 1.500.000€.", "Απαιτείται άδεια λειτουργίας όπου προβλέπεται και ισχύοντα μέτρα πυροπροστασίας.", "Για κλοπή περιεχομένου απαιτούνται ικανοποιητικά μέτρα προστασίας, δηλωμένα στην πρόταση.", "Για σεισμό απαιτείται έντυπο σεισμού. Για κτίρια προ του 1960 απαιτείται δελτίο τρωτότητας μηχανικού.", "Δεν μπορούν να αφαιρεθούν μεμονωμένες καλύψεις από τα πακέτα."], "home": ["FULL [HOME]: προϊόν κατοικίας με πακέτα Α, Β, C, D και προαιρετικό σεισμό.", "VIP: για συνολική ασφαλιζόμενη αξία κατοικίας από 300.000€ έως 15.000.000€.", "Για κτίρια προ του 1950 παρέχεται ασφάλιση αποκλειστικά σε τρέχουσα πραγματική αξία.", "Για σεισμό απαιτείται υπογεγραμμένο έντυπο σεισμού.", "Για κτίρια προ του 1960 απαιτείται δελτίο τρωτότητας μηχανικού."]};
let selectedProduct="business_plus", selectedPackage="full";
const el=id=>document.getElementById(id);
function product(){return DATA[selectedProduct]}
function order(k){const pref=["simple","composite","full","A","B","C","D","vip"];return Object.keys(DATA[k].packages).sort((a,b)=>pref.indexOf(a)-pref.indexOf(b))}
function covers(pk,pack){const p=DATA[pk].packages[pack];let arr=[];if(p.inherits)arr=covers(pk,p.inherits);return arr.concat(p.coverages)}
function initProducts(){el("product").innerHTML="";Object.entries(DATA).forEach(([k,p])=>{const o=document.createElement("option");o.value=k;o.textContent=p.label;el("product").appendChild(o)});el("product").value=selectedProduct}
function initBusinesses(q=""){q=q.toLowerCase().trim();const list=BUSINESS_NAMES.filter(x=>x.toLowerCase().includes(q));const s=el("businessType"),cur=s.value;s.innerHTML="";list.forEach(x=>{const o=document.createElement("option");o.value=x;o.textContent=x;s.appendChild(o)});if(list.includes(cur))s.value=cur;else if(list.length)s.value=list[0];el("businessCount").textContent=list.length+" δραστηριότητες"}
function renderPackages(){const box=el("packageButtons");box.innerHTML="";const keys=order(selectedProduct);if(!keys.includes(selectedPackage))selectedPackage=keys[keys.length-1];keys.forEach(k=>{const b=document.createElement("button");b.type="button";b.textContent=DATA[selectedProduct].packages[k].label;b.className=k===selectedPackage?"active":"";b.onclick=()=>{selectedPackage=k;render()};box.appendChild(b)})}
function renderCoverages(){const list=covers(selectedProduct,selectedPackage);el("help").textContent=list.length+" καλύψεις για "+DATA[selectedProduct].packages[selectedPackage].label;const box=el("coverages");box.innerHTML="";list.forEach(c=>{const b=document.createElement("button");b.type="button";b.className="coverage";b.innerHTML=c.name+'<br><span class="tag">'+c.source+'</span>';b.onclick=()=>show(c);box.appendChild(b)})}
function show(c){el("mTitle").textContent=c.name;el("mLimit").textContent=c.limit;el("mDed").textContent=c.deductible;el("mMean").textContent=c.meaning;el("mExc").textContent=c.exclusions||"Δεν αναγράφεται ειδική εξαίρεση στον πίνακα της συγκεκριμένης κάλυψης.";el("mUw").textContent=c.uw||"Έλεγχος σύμφωνα με τους κανόνες ανάληψης του προϊόντος και την πρόταση ασφάλισης.";el("mSource").textContent=c.source;el("modal").classList.add("show")}
function renderRules(){const rules=UNDERWRITING[product().kind]||[];el("rules").innerHTML="<ul>"+rules.map(x=>"<li>"+x+"</li>").join("")+"</ul>"}
function renderSummary(){const p=product(), pack=p.packages[selectedPackage].label, extra=p.kind==="business"?" · "+(el("businessType").value||""):"";el("summary").textContent=p.label+" · "+pack+extra;el("badge").textContent=p.kind==="business"?"Επιχείρηση":"Κατοικία"}
function render(){el("businessBox").classList.toggle("hidden",product().kind!=="business");renderPackages();renderCoverages();renderRules();renderSummary()}
function analyze(){render();const list=covers(selectedProduct,selectedPackage), notes=el("notes").value.trim();el("note").innerHTML="<p><strong>"+el("summary").textContent+"</strong></p><p>Εμφανίζονται μόνο οι καλύψεις του επιλεγμένου πακέτου. Κάθε κάλυψη έχει popup με όριο, απαλλαγή, ερμηνεία και πηγή PDF.</p><p><strong>Σύνολο καλύψεων:</strong> "+list.length+"</p>"+(notes?"<p><strong>Σχόλια:</strong> "+notes.replace(/[&<>]/g,m=>({"&":"&amp;","<":"&lt;",">":"&gt;"}[m]))+"</p>":"")}
function copyResult(){const text=[el("summary").textContent,...covers(selectedProduct,selectedPackage).map(c=>c.name+"\nΌριο: "+c.limit+"\nΑπαλλαγή: "+c.deductible+"\nΠηγή: "+c.source)].join("\n\n");navigator.clipboard.writeText(text).then(()=>{el("toast").classList.add("show");setTimeout(()=>el("toast").classList.remove("show"),1500)})}
el("product").onchange=e=>{selectedProduct=e.target.value;selectedPackage=order(selectedProduct).slice(-1)[0];render()};el("businessSearch").oninput=e=>{initBusinesses(e.target.value);renderSummary()};el("businessType").onchange=renderSummary;el("analyzeBtn").onclick=analyze;el("copyBtn").onclick=copyResult;el("mClose").onclick=()=>el("modal").classList.remove("show");el("modal").onclick=e=>{if(e.target.id==="modal")el("modal").classList.remove("show")};document.addEventListener("keydown",e=>{if(e.key==="Escape")el("modal").classList.remove("show")});
initProducts();initBusinesses();render();


// ===== v11 SEPARATE FIRE / AUTO SECTIONS =====
let AUTO = null;
let activeBranch = null;
let autoReady = false;

function isAuto() {
  return String(selectedProduct).startsWith("auto:");
}

function autoProduct() {
  if (!AUTO || !isAuto()) return null;
  return AUTO.products.find(p => p.id === selectedProduct.split(":")[1]) || null;
}

function autoPack() {
  const product = autoProduct();
  return product ? product.packages.find(p => p.id === selectedPackage) || null : null;
}

function allowedAutoProductIds() {
  const use = el("vehicleUse")?.value || "eix";
  if (use === "eix") return ["fullauto", "autoprotect"];
  if (["fix", "fix_agro", "fix_fridge"].includes(use)) return ["fulltruck"];
  return [];
}

function autoCoverages() {
  const pack = autoPack();
  if (!pack || !AUTO) return [];
  return Object.entries(pack.statuses)
    .filter(([, status]) => status !== "unavailable")
    .map(([id, status]) => ({ ...AUTO.coverages[id], status }));
}

function setBranchPanels(branch) {
  const fire = branch === "fire";
  el("fireResultPanel")?.classList.toggle("hidden", !fire);
  el("autoResultPanel")?.classList.toggle("hidden", fire);
  el("businessBox")?.classList.toggle("hidden", !fire || selectedProduct === "home");
  el("autoBox")?.classList.toggle("hidden", fire);
}

function refreshAutoProductOptions() {
  if (!AUTO) return;

  const select = el("product");
  [...select.options]
    .filter(option => String(option.value).startsWith("auto:"))
    .forEach(option => option.remove());

  const allowed = allowedAutoProductIds();
  AUTO.products
    .filter(product => allowed.includes(product.id))
    .forEach(product => {
      const option = document.createElement("option");
      option.value = "auto:" + product.id;
      option.textContent = product.title;
      select.appendChild(option);
    });
}

async function loadAuto() {
  try {
    const response = await fetch("auto.json", { cache: "no-store" });
    if (!response.ok) throw new Error("Αποτυχία φόρτωσης auto.json");
    AUTO = await response.json();
    autoReady = true;
    refreshAutoProductOptions();

    const button = el("autoBranchBtn");
    button.disabled = false;
    button.classList.remove("loading");
  } catch (error) {
    console.error(error);
    const button = el("autoBranchBtn");
    button.disabled = true;
    button.classList.add("loading");
    const text = button.querySelector(".branch-description");
    if (text) text.textContent = "Δεν φορτώθηκαν τα στοιχεία αυτοκινήτου. Κάνε ανανέωση.";
  }
}

const originalFireRender = render;
const originalFireAnalyze = analyze;
const originalFireCopy = copyResult;

function renderAuto() {
  setBranchPanels("auto");

  const product = autoProduct();
  if (!product) {
    el("packageButtons").innerHTML = "";
    el("autoCoverages").innerHTML = "";
    el("autoHelp").textContent = "Δεν βρέθηκε διαθέσιμο πακέτο αυτοκινήτου.";
    el("autoRules").innerHTML = "<p>Απαιτείται ανανέωση της σελίδας.</p>";
    el("autoSummary").textContent = "Αυτοκίνητο";
    el("autoBadge").textContent = "Σφάλμα";
    return;
  }

  if (!product.packages.some(p => p.id === selectedPackage)) {
    selectedPackage = product.packages[0].id;
  }

  const packageBox = el("packageButtons");
  packageBox.innerHTML = "";

  product.packages.forEach(pack => {
    const button = document.createElement("button");
    button.type = "button";
    button.textContent = pack.title;
    button.className = pack.id === selectedPackage ? "active" : "";
    button.addEventListener("click", () => {
      selectedPackage = pack.id;
      renderAuto();
    });
    packageBox.appendChild(button);
  });

  const list = autoCoverages();
  el("autoHelp").textContent =
    `${list.length} καλύψεις για ${autoPack().title}. Πάτησε σε μία κάλυψη για λεπτομέρειες.`;

  const grid = el("autoCoverages");
  grid.innerHTML = "";

  list.forEach(coverage => {
    const button = document.createElement("button");
    button.type = "button";
    button.className = "coverage";
    const status = coverage.status === "required" ? "Υποχρεωτική" : "Προαιρετική";
    button.innerHTML =
      `${escapeHtml(coverage.name)}<br><span class="tag">${status} · ${escapeHtml(coverage.source)}</span>`;

    button.addEventListener("click", () => {
      el("mTitle").textContent = coverage.name;
      el("mLimit").textContent = coverage.limit;
      el("mDed").textContent = coverage.deductible;
      el("mMean").textContent = coverage.meaning;
      el("mExc").textContent =
        "Ισχύουν οι γενικοί και ειδικοί όροι της συγκεκριμένης κάλυψης.";
      el("mUw").textContent =
        "Ελέγχονται η χρήση, η ηλικία, η αξία, η κατάσταση του οχήματος και η ανάγκη προασφαλιστικού ελέγχου ή έγκρισης.";
      el("mSource").textContent = coverage.source;
      el("modal").classList.add("show");
    });

    grid.appendChild(button);
  });

  el("autoRules").innerHTML =
    "<ul>" + product.rules.map(rule => `<li>${escapeHtml(rule)}</li>`).join("") + "</ul>";

  el("autoSummary").textContent = `${product.title} · ${autoPack().title}`;
  el("autoBadge").textContent = "Αυτοκίνητο";
}

render = function () {
  if (isAuto()) {
    renderAuto();
    return;
  }

  setBranchPanels("fire");
  originalFireRender();
};

analyze = function () {
  if (!isAuto()) {
    setBranchPanels("fire");
    originalFireAnalyze();
    return;
  }

  renderAuto();

  const product = autoProduct();
  const pack = autoPack();
  const age = Number(el("vehicleAge").value || 0);
  const value = Number(el("vehicleValue").value || 0);
  const special = el("vehicleSpecial").value;
  const use = el("vehicleUse").value;
  const warnings = [];
  let requiresInspection = false;
  let requiresApproval = false;
  let eligible = true;

  if (product.id === "fullauto") {
    if (selectedPackage === "v3" && age > 15) {
      warnings.push("Το Full Value παρέχεται για οχήματα έως 15 ετών.");
      eligible = false;
    }
    if (selectedPackage === "v4" && age > 12) {
      warnings.push("Το Full Premium παρέχεται για οχήματα έως 12 ετών.");
      eligible = false;
    }
    if (selectedPackage === "v3" && value && value < 2000) {
      warnings.push("Ελάχιστη ασφαλιστική αξία Full Value: 2.000€.");
      eligible = false;
    }
    if (selectedPackage === "v4" && value && value < 3000) {
      warnings.push("Ελάχιστη ασφαλιστική αξία Full Premium: 3.000€.");
      eligible = false;
    }
  }

  if (product.id === "autoprotect") {
    if (["extra", "premium"].includes(selectedPackage) && age > 15) {
      warnings.push("Τα Auto Protect Extra και Premium παρέχονται έως 15 έτη.");
      eligible = false;
    }
    if (selectedPackage === "extra" && value && value < 2000) {
      warnings.push("Ελάχιστη ασφαλιστική αξία Auto Protect Extra: 2.000€.");
      eligible = false;
    }
    if (selectedPackage === "premium" && value && value < 3000) {
      warnings.push("Ελάχιστη ασφαλιστική αξία Auto Protect Premium: 3.000€.");
      eligible = false;
    }
  }

  if (product.id === "fulltruck" && age > 12) {
    warnings.push("Τα FullTruck παρέχονται για επιλέξιμες χρήσεις έως 12 ετών.");
    eligible = false;
  }

  if (value > 50000 || special === "high") {
    warnings.push("Για αξία άνω των 50.000€ απαιτείται ειδική προσφορά από την Εταιρία.");
    requiresApproval = true;
  }

  if (special === "smart") {
    warnings.push("Για Smart απαιτείται ειδική έγκριση και δεν παρέχεται αντικατάσταση λόγω κλοπής.");
    requiresApproval = true;
  }

  if (special === "moto" || use === "moto") {
    warnings.push("Δεν παρέχεται κάλυψη κλοπής σε μηχανές και μοτοποδήλατα.");
    requiresApproval = true;
  }

  if (special === "transfer") {
    warnings.push("Για transfer / μεταφορά προσωπικού απαιτείται ειδική προσφορά.");
    requiresApproval = true;
  }

  const mixed = autoCoverages().some(c => c.name.includes("Ζημιές Ιδίου"));
  if (mixed) {
    warnings.push("Η Μικτή απαιτεί προασφαλιστικό έλεγχο και έγκριση της Εταιρίας.");
    requiresInspection = true;
    requiresApproval = true;
  }

  const notes = el("notes").value.trim();
  const statusText = eligible ? "Επιλέξιμο βάσει βασικών ορίων" : "Μη επιλέξιμο βάσει βασικών ορίων";

  el("autoBadge").textContent = eligible ? "Επιλέξιμο" : "Έλεγχος";
  el("autoNote").innerHTML = `
    <div class="analysis-status ${eligible ? "ok" : "warning"}">
      <strong>${statusText}</strong>
    </div>
    <p><strong>Προϊόν:</strong> ${escapeHtml(product.title)}</p>
    <p><strong>Πακέτο:</strong> ${escapeHtml(pack.title)}</p>
    <p><strong>Ηλικία οχήματος:</strong> ${age || "Δεν δηλώθηκε"}</p>
    <p><strong>Αξία οχήματος:</strong> ${value ? value.toLocaleString("el-GR") + "€" : "Δεν δηλώθηκε"}</p>
    <p><strong>Προασφαλιστικός έλεγχος:</strong> ${requiresInspection ? "Ναι" : "Δεν προκύπτει από τα δηλωμένα στοιχεία"}</p>
    <p><strong>Έγκριση Εταιρίας:</strong> ${requiresApproval ? "Ναι" : "Δεν προκύπτει από τα δηλωμένα στοιχεία"}</p>
    ${warnings.length
      ? `<p><strong>Παρατηρήσεις ανάληψης:</strong></p>
         <ul>${warnings.map(w => `<li>${escapeHtml(w)}</li>`).join("")}</ul>`
      : "<p><strong>Δεν εντοπίστηκε προφανής υπέρβαση των βασικών ορίων.</strong></p>"}
    ${notes ? `<p><strong>Σχόλια:</strong> ${escapeHtml(notes)}</p>` : ""}
  `;

  el("autoResultPanel").scrollIntoView({ behavior: "smooth", block: "start" });
};

copyResult = async function () {
  if (!isAuto()) {
    originalFireCopy();
    return;
  }

  const text = [
    el("autoSummary").textContent,
    el("autoNote").innerText,
    "",
    "Καλύψεις:",
    ...autoCoverages().map(c =>
      `${c.name} (${c.status === "required" ? "Υποχρεωτική" : "Προαιρετική"})`
    )
  ].join("\n");

  await navigator.clipboard.writeText(text);
  el("toast").classList.add("show");
  setTimeout(() => el("toast").classList.remove("show"), 1500);
};

function applyBranchProductFilter() {
  const select = el("product");

  [...select.options].forEach(option => {
    const autoOption = String(option.value).startsWith("auto:");
    option.hidden =
      activeBranch === "fire" ? autoOption :
      activeBranch === "auto" ? !autoOption :
      false;
  });
}

function resetSharedInputs() {
  el("notes").value = "";
  el("note").innerHTML = "Πάτησε «Ανάλυση underwriting» για σύνοψη.";
  el("autoNote").innerHTML =
    "Συμπλήρωσε τα στοιχεία του οχήματος και πάτησε «Ανάλυση underwriting».";
}

function showLanding() {
  activeBranch = null;
  resetSharedInputs();
  el("landingScreen").classList.remove("hidden");
  el("mainApplication").classList.add("hidden");
  window.scrollTo({ top: 0, behavior: "smooth" });
}

function openFireBranch() {
  activeBranch = "fire";

  const select = el("product");
  const option = [...select.options].find(o => !String(o.value).startsWith("auto:"));

  if (option) {
    selectedProduct = option.value;
    select.value = option.value;
    const packages = packageOrder(selectedProduct);
    selectedPackage = packages[packages.length - 1];
  }

  applyBranchProductFilter();
  el("landingScreen").classList.add("hidden");
  el("mainApplication").classList.remove("hidden");
  setBranchPanels("fire");
  originalFireRender();
  window.scrollTo({ top: 0, behavior: "smooth" });
}

function openAutoBranch() {
  if (!autoReady || !AUTO) return;

  activeBranch = "auto";
  refreshAutoProductOptions();

  const select = el("product");
  const option = [...select.options].find(o => String(o.value).startsWith("auto:"));

  el("landingScreen").classList.add("hidden");
  el("mainApplication").classList.remove("hidden");
  setBranchPanels("auto");

  if (!option) {
    el("packageButtons").innerHTML = "";
    el("autoCoverages").innerHTML = "";
    el("autoHelp").textContent =
      "Δεν υπάρχει τυποποιημένο πακέτο για την επιλεγμένη χρήση.";
    el("autoRules").innerHTML =
      "<p><strong>Απαιτείται ειδική προσφορά / έγκριση Κλάδου.</strong></p>";
    return;
  }

  selectedProduct = option.value;
  select.value = option.value;
  selectedPackage = autoProduct().packages[0].id;
  applyBranchProductFilter();
  renderAuto();
  window.scrollTo({ top: 0, behavior: "smooth" });
}

el("fireBranchBtn").addEventListener("click", openFireBranch);

el("autoBranchBtn").disabled = true;
el("autoBranchBtn").classList.add("loading");
el("autoBranchBtn").addEventListener("click", openAutoBranch);

el("backHomeBtn")?.addEventListener("click", showLanding);

const originalProductChange = el("product").onchange;
el("product").onchange = event => {
  const value = event.target.value;

  if (activeBranch === "auto" && String(value).startsWith("auto:")) {
    selectedProduct = value;
    selectedPackage = autoProduct()?.packages?.[0]?.id || "";
    renderAuto();
    return;
  }

  if (activeBranch === "fire" && !String(value).startsWith("auto:")) {
    originalProductChange?.(event);
    setBranchPanels("fire");
  }
};

el("vehicleUse")?.addEventListener("change", () => {
  refreshAutoProductOptions();
  const allowed = allowedAutoProductIds();

  if (!allowed.length) {
    el("packageButtons").innerHTML = "";
    el("autoCoverages").innerHTML = "";
    el("autoHelp").textContent =
      "Για αυτή τη χρήση δεν υπάρχει τυποποιημένο πακέτο στο διαθέσιμο εγχειρίδιο.";
    el("autoRules").innerHTML =
      "<p><strong>Απαιτείται εξατομικευμένη προσφορά / έγκριση Κλάδου.</strong></p>";
    el("autoSummary").textContent = "Αυτοκίνητο · Ειδική χρήση";
    el("autoBadge").textContent = "Ειδική έγκριση";
    return;
  }

  selectedProduct = "auto:" + allowed[0];
  el("product").value = selectedProduct;
  selectedPackage = autoProduct()?.packages?.[0]?.id || "";
  renderAuto();
});

showLanding();
loadAuto();
